import React from 'react';
import Navbar from '../../components/common/Navbar';
import Sidebar from '../../components/common/Sidebar';

const Recommendations = () => {
  const userName = localStorage.getItem('userName') || 'Student';

  const recommendations = [
    {
      type: 'Practice',
      title: 'Practice more on Graphs',
      description: 'Your accuracy in graph problems is below average. Focus on BFS and DFS algorithms.',
      priority: 'High',
      icon: '📚',
      color: 'red',
    },
    {
      type: 'Speed',
      title: 'Your solving time increased in Recursion',
      description: 'Try to solve recursion problems faster. Practice more basic recursion patterns.',
      priority: 'Medium',
      icon: '⏱️',
      color: 'yellow',
    },
    {
      type: 'Retry',
      title: 'Retry Logic questions',
      description: 'You have high retry counts in logic problems. Review fundamental concepts.',
      priority: 'Medium',
      icon: '🔄',
      color: 'yellow',
    },
    {
      type: 'Accuracy',
      title: 'Focus on accuracy in Arrays',
      description: 'Your speed is good but accuracy needs improvement. Take time to understand problems.',
      priority: 'Low',
      icon: '🎯',
      color: 'blue',
    },
    {
      type: 'Improvement',
      title: 'Great progress in Strings!',
      description: 'Keep up the excellent work. Your accuracy and speed both improved.',
      priority: 'Info',
      icon: '🌟',
      color: 'green',
    },
    {
      type: 'Review',
      title: 'Review Tree Traversal',
      description: 'Revisit inorder, preorder, and postorder traversal concepts.',
      priority: 'High',
      icon: '🌳',
      color: 'red',
    },
  ];

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'High': return 'border-red-500 bg-red-50';
      case 'Medium': return 'border-yellow-500 bg-yellow-50';
      case 'Low': return 'border-blue-500 bg-blue-50';
      case 'Info': return 'border-green-500 bg-green-50';
      default: return 'border-gray-500 bg-gray-50';
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <Navbar role="Student" userName={userName} />
      <div className="flex">
        <Sidebar role="student" />
        <main className="flex-1 p-6">
          <h2 className="text-3xl font-bold text-gray-800 mb-6">Recommendations</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {recommendations.map((rec, index) => (
              <div
                key={index}
                className={`rounded-lg shadow-lg p-6 border-l-4 ${getPriorityColor(rec.priority)} hover:shadow-xl transition`}
              >
                <div className="flex items-start space-x-4">
                  <div className="text-4xl">{rec.icon}</div>
                  <div className="flex-1">
                    <div className="flex justify-between items-start mb-2">
                      <h3 className="text-lg font-bold text-gray-800">{rec.title}</h3>
                      <span className={`text-xs px-2 py-1 rounded-full font-semibold ${
                        rec.priority === 'High' ? 'bg-red-200 text-red-800' :
                        rec.priority === 'Medium' ? 'bg-yellow-200 text-yellow-800' :
                        rec.priority === 'Low' ? 'bg-blue-200 text-blue-800' :
                        'bg-green-200 text-green-800'
                      }`}>
                        {rec.priority}
                      </span>
                    </div>
                    <p className="text-gray-700 text-sm">{rec.description}</p>
                    <div className="mt-3">
                      <span className="text-xs text-gray-500 bg-white px-2 py-1 rounded">{rec.type}</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </main>
      </div>
    </div>
  );
};

export default Recommendations;
